---
import type { HTMLAttributes } from "astro/types";
import { cn } from "@/lib/utils";

interface Props extends HTMLAttributes<"div"> {
  heading?: string;
  value?: string;
  forceMount?: boolean;
  class?: string;
}

const {
  heading,
  value,
  forceMount = false,
  class: className = "",
  ...rest
} = Astro.props as Props;
---

<div
  {...rest}
  role="group"
  data-slot="command-group"
  data-value={value}
  data-force-mount={forceMount ? "true" : undefined}
  class={cn("text-foreground **:[[cmdk-group-heading]]:text-muted-foreground overflow-hidden p-1 **:[[cmdk-group-heading]]:px-2 **:[[cmdk-group-heading]]:py-1.5 **:[[cmdk-group-heading]]:text-xs **:[[cmdk-group-heading]]:font-medium", className)}
>
  {
    heading && (
      <div data-slot="command-group-heading" cmdk-group-heading>
        {heading}
      </div>
    )
  }
  <slot />
</div>

---
import { SearchIcon } from "@lucide/astro";
import type { HTMLAttributes } from "astro/types";
import { cn } from "@/lib/utils";
import { InputGroup, InputGroupAddon } from "../input-group";
import { inputGroupControlClasses } from "../input-group/controlClasses";

interface Props extends HTMLAttributes<"input"> {
  class?: string;
}

const { class: className = "", ...rest } = Astro.props as Props;
---

<div data-slot="command-input-wrapper" class="p-1 pb-0">
  <InputGroup size="sm" class="bg-input/30 border-input/30 h-8! rounded-lg! shadow-none! *:data-[slot=input-group-addon]:pl-2!">
    <input
      data-input-group-control
      data-slot="command-input"
      autocomplete="off"
      autocorrect="off"
      spellcheck="false"
      class={cn(
        "rounded-none border-0 bg-transparent shadow-none ring-0 focus-visible:ring-0 disabled:bg-transparent aria-invalid:ring-0 dark:bg-transparent dark:disabled:bg-transparent w-full text-sm outline-hidden disabled:cursor-not-allowed disabled:opacity-50",
        inputGroupControlClasses,
        className,
      )}
      {...rest}
    />
    <InputGroupAddon align="inline-end">
      <SearchIcon
        data-slot="command-input-icon"
        class="size-4 shrink-0 opacity-50 pointer-events-none"
      />
    </InputGroupAddon>
  </InputGroup>
</div>

---
import type { HTMLAttributes } from "astro/types";
import { cn } from "@/lib/utils";

interface Props extends HTMLAttributes<"div"> {
  value?: string;
  label?: string;
  keywords?: string | string[];
  disabled?: boolean;
  forceMount?: boolean;
  class?: string;
}

const {
  value,
  label,
  keywords,
  disabled = false,
  forceMount = false,
  class: className = "",
  ...rest
} = Astro.props as Props;

const keywordValue = Array.isArray(keywords) ? keywords.join(", ") : keywords;
---

<div
  {...rest}
  data-slot="command-item"
  data-value={value}
  data-label={label}
  data-keywords={keywordValue}
  data-disabled={disabled ? "true" : undefined}
  data-force-mount={forceMount ? "true" : undefined}
  class={cn(
    "data-selected:bg-muted data-selected:text-foreground data-selected:*:[svg]:text-foreground relative flex cursor-default items-center gap-2 rounded-sm px-2 py-1.5 text-sm outline-hidden select-none in-data-[slot=dialog-content]:rounded-lg! [&_svg:not([class*='size-'])]:size-4 group/command-item data-[disabled=true]:pointer-events-none data-[disabled=true]:opacity-50 [&_svg]:pointer-events-none [&_svg]:shrink-0",
    className,
  )}
>
  <slot />
</div>

